.darma-loader-loading-io-32 {
  display: inline-block;
  width: 56px;
  height: 56px;
  border-radius: 50%;
  border: 5px solid color-mix(in srgb, var(--loader-secondary-color, #fed7aa) 35%, transparent);
  border-top-color: var(--loader-color, #f97316);
  border-right-color: var(--loader-color, #f97316);
  animation: darma-loader-loading-io-32-spin 0.85s cubic-bezier(.55,.15,.45,.85) infinite;
}
.darma-loader-loading-io-32::after {
  content: "";
  display: block;
  width: calc(100% - 16px);
  height: calc(100% - 16px);
  margin: 4px;
  border-radius: 50%;
  border: 4px solid transparent;
  border-bottom-color: var(--loader-secondary-color, #fed7aa);
  animation: darma-loader-loading-io-32-spin 0.59s linear infinite reverse;
}
@keyframes darma-loader-loading-io-32-spin { to { transform: rotate(360deg); } }

